const TOPIC_TASK = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Task_Queue";
const TOPIC_SYNC = "Henkelv2/Shanghai/Logistics/External/Integration/State/Sync_Status";

let newDN = msg.payload;

let taskData = global.get('internal_task_queue') || { last_updated: 0, queue: [] };
if (taskData.queue) {
    taskData.queue = taskData.queue.filter(t => t.dn_no !== newDN.dn_no);
} else {
    taskData.queue = [];
}

let newTask = {
    task_id: "T-" + Math.floor(Math.random() * 10000),
    dn_no: newDN.dn_no || "UNKNOWN",
    type: newDN.doc_type === "OUTBOUND" ? "PICK" : "PUTAWAY",
    location: "STAGING-01",
    sku: newDN.sku,
    status: "NEW",
    timestamp: Date.now()
};

taskData.queue.push(newTask);
taskData.last_updated = Math.floor(Date.now() / 1000);
global.set('internal_task_queue', taskData);

let msgTask = {
    topic: TOPIC_TASK,
    payload: {
        "version": "1.0",
        "topics": [{ "path": TOPIC_TASK, "type": "state", "value": taskData }]
    }
};

let syncData = global.get('external_sync_status') || { last_updated: 0, sync_records: [] };
if (syncData.sync_records) {
    syncData.sync_records = syncData.sync_records.filter(r => r.ref_no !== newDN.dn_no);
} else {
    syncData.sync_records = [];
}

let newRecord = {
    ref_no: newDN.dn_no,
    type: newDN.doc_type === "OUTBOUND" ? "OUTBOUND_DN" : "INBOUND_ASN",
    "3pl_provider": "INTERNAL_FLEET",
    sku: newDN.sku,
    sync_status: "PENDING",
    timestamp: Date.now()
};

syncData.sync_records.unshift(newRecord);
if (syncData.sync_records.length > 10) syncData.sync_records.pop();
syncData.last_updated = Math.floor(Date.now() / 1000);
global.set('external_sync_status', syncData);

let msgSync = {
    topic: TOPIC_SYNC,
    payload: {
        "version": "1.0",
        "topics": [{ "path": TOPIC_SYNC, "type": "state", "value": syncData }]
    }
};

return [[msgTask, msgSync]];

