let inboundCost  = (newDN.doc_type === "INBOUND") ? (qty * rates.basic.inbound) : 0;
let outboundCost = (newDN.doc_type === "OUTBOUND") ? (qty * rates.basic.outbound) : 0;
let storageCost  = qty * storage_days * rates.basic.storage;
