    vas_cost: 0,
    total_cost: totalBasic
};

let allDNs = global.get('dn_db') || {};
allDNs[newDN.dn_no] = financeRecord;
global.set('dn_db', allDNs);

let msgOps = {
    topic: TOPIC_SYNC,
    payload: {
        "version": "1.0",
        "topics": [{ "path": TOPIC_SYNC, "type": "state", "value": syncData }]
