const TOPIC_DN_STATE = "Henkelv2/Shanghai/Logistics/Outbound/State/DN_Workflow";

let action = msg.payload;
// Expected: { dn_no, reason, action: 'HOLD' }

// 1. Get order DB
let dnDB = global.get('outbound_dn_db') || { items: [] };

// 2. Find the order
let orderIndex = dnDB.items.findIndex(o => o.dn_no === action.dn_no || o.id === action.dn_no);
if (orderIndex === -1) {
    node.warn("Hold Error: Order not found " + action.dn_no);
    return null;
}

let order = dnDB.items[orderIndex];

// 3. Validate - can only hold RELEASED or WAVE_ASSIGNED orders
const canHold = ['RELEASED', 'WAVE_ASSIGNED', 'NEW', 'APPROVED'].includes((order.status || '').toUpperCase());
if (!canHold) {
    node.warn("Hold Error: Cannot hold order in status " + order.status);
    return null;
}

// 4. Store previous status and update
order.previous_status = order.status;
order.status = 'ON_HOLD';
order.on_hold = true;
order.hold_reason = action.reason || 'Manual hold';
order.hold_timestamp = Date.now();
order.hold_by = action.operator || 'System';

// 5. If in a wave, remove from wave
if (order.wave_id) {
    let waveDB = global.get('wave_db') || { items: [] };
    let wave = waveDB.items.find(w => w.wave_id === order.wave_id);
    if (wave) {
        wave.delivery_ids = (wave.delivery_ids || []).filter(id => id !== order.dn_no && id !== order.id);
        wave.delivery_count = wave.delivery_ids.length;
        global.set('wave_db', waveDB);
    }
    order.previous_wave_id = order.wave_id;
    order.wave_id = null;
}

// 6. Save
global.set('outbound_dn_db', dnDB);

// 7. Publish
msg.topic = TOPIC_DN_STATE;
msg.payload = {
    version: "1.0",
    topics: [{ path: TOPIC_DN_STATE, type: "state", value: dnDB }]
};

return msg;

