const TOPIC_DN_STATE = "Henkelv2/Shanghai/Logistics/Outbound/State/DN_Workflow";

let action = msg.payload;
// Expected: { dn_no, action: 'RELEASE_HOLD' }

// 1. Get order DB
let dnDB = global.get('outbound_dn_db') || { items: [] };

// 2. Find the order
let orderIndex = dnDB.items.findIndex(o => o.dn_no === action.dn_no || o.id === action.dn_no);
if (orderIndex === -1) {
    node.warn("Release Hold Error: Order not found " + action.dn_no);
    return null;
}

let order = dnDB.items[orderIndex];

// 3. Validate - must be on hold
if ((order.status || '').toUpperCase() !== 'ON_HOLD') {
    node.warn("Release Hold Error: Order not on hold. Current status: " + order.status);
    return null;
}

// 4. Restore previous status or default to RELEASED
order.status = order.previous_status || 'RELEASED';
order.on_hold = false;
order.hold_reason = null;
order.released_hold_at = Date.now();
order.released_hold_by = action.operator || 'System';

// Clear previous status tracking
delete order.previous_status;
delete order.hold_timestamp;
delete order.hold_by;

// 5. Save
global.set('outbound_dn_db', dnDB);

// 6. Publish
msg.topic = TOPIC_DN_STATE;
msg.payload = {
    version: "1.0",
    topics: [{ path: TOPIC_DN_STATE, type: "state", value: dnDB }]
};

return msg;

// TOPICS
const TOPIC_WAVE_STATE = "Henkelv2/Shanghai/Logistics/Outbound/State/Wave_List";
const TOPIC_DN_STATE = "Henkelv2/Shanghai/Logistics/Outbound/State/DN_Workflow";

let action = msg.payload;
// Expected: { wave_id?, ship_date, carrier, route, pick_method, delivery_ids: [] }

// 1. Get DBs
let waveDB = global.get('wave_db') || { items: [] };
let dnDB = global.get('outbound_dn_db') || { items: [] };

// 2. Create wave
let newWave = {
    wave_id: action.wave_id || 'WAVE-' + Date.now(),
    status: 'PLANNED',
    ship_date: action.ship_date || null,
    carrier: action.carrier || null,
    route: action.route || null,
    pick_method: action.pick_method || 'BATCH',
    delivery_ids: action.delivery_ids || [],
    delivery_count: (action.delivery_ids || []).length,
    line_count: 0,
    picks_completed: 0,
    picks_total: 0,
    created_at: Date.now(),
    created_by: action.operator || 'System'
};

// 3. Count lines from deliveries
let lineCount = 0;
action.delivery_ids?.forEach(dnId => {
    let order = dnDB.items.find(o => o.dn_no === dnId || o.id === dnId);
    if (order) {
        lineCount += (order.lines || []).length;
        // Update order status and wave assignment
        order.wave_id = newWave.wave_id;
        order.status = 'WAVE_ASSIGNED';
    }
});
newWave.line_count = lineCount;

// 4. Add to DB
waveDB.items.unshift(newWave);

// 5. Save
global.set('wave_db', waveDB);
global.set('outbound_dn_db', dnDB);

// 6. Prepare outputs
let msgWave = {
    topic: TOPIC_WAVE_STATE,
    payload: { version: "1.0", topics: [{ path: TOPIC_WAVE_STATE, type: "state", value: waveDB }] }
};

let msgDN = {
    topic: TOPIC_DN_STATE,
    payload: { version: "1.0", topics: [{ path: TOPIC_DN_STATE, type: "state", value: dnDB }] }
};

return [msgWave, msgDN];

// TOPICS
const TOPIC_WAVE_STATE = "Henkelv2/Shanghai/Logistics/Outbound/State/Wave_List";
const TOPIC_DN_STATE = "Henkelv2/Shanghai/Logistics/Outbound/State/DN_Workflow";
const TOPIC_INVENTORY = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Inventory_Level";
const TOPIC_TASKS = "Henkelv2/Shanghai/Logistics/Outbound/State/Picking_Tasks";

let action = msg.payload;
// Expected: { wave_id }

// 1. Get DBs
let waveDB = global.get('wave_db') || { items: [] };
let dnDB = global.get('outbound_dn_db') || { items: [] };
let inventory = global.get('internal_stock_list') || [];
let taskDB = global.get('outbound_task_db') || { items: [] };

// 2. Find wave
let wave = waveDB.items.find(w => w.wave_id === action.wave_id);
if (!wave) {
    node.warn("Release Wave Error: Wave not found " + action.wave_id);
    return null;
}

if (wave.status !== 'PLANNED') {
    node.warn("Release Wave Error: Wave not in PLANNED status");
    return null;
}

// 3. Update wave status
wave.status = 'RELEASED';
wave.released_at = Date.now();
wave.released_by = action.operator || 'System';

// 4. Process each delivery in the wave - Run allocation
let totalPicks = 0;
let allocationResults = [];

wave.delivery_ids.forEach(dnId => {
    let order = dnDB.items.find(o => o.dn_no === dnId || o.id === dnId);
    if (!order) return;

    order.status = 'ALLOCATING';

    // Simple FEFO allocation logic
    (order.lines || []).forEach(line => {
        // Find available stock
        let candidates = inventory.filter(item =>
            item.sku === line.code &&
            item.status === 'AVAILABLE'
        );

        // Sort by expiry (FEFO)
        candidates.sort((a, b) => {
            let dateA = a.expiry_date || 9999999999999;
            let dateB = b.expiry_date || 9999999999999;
            return dateA - dateB;
        });

        let needed = line.qty || 0;
        let allocated = 0;

        for (let batch of candidates) {
            if (needed <= 0) break;
            if (batch.qty <= 0) continue;

            let takeQty = Math.min(batch.qty, needed);

            // Mark batch as allocated
            batch.status = 'ALLOCATED';
            batch.allocated_to = order.dn_no || order.id;

            // Create pick task
            let newTask = {
                task_id: 'PICK-' + Date.now() + '-' + Math.floor(Math.random() * 1000),
                wave_id: wave.wave_id,
                dn_no: order.dn_no || order.id,
                batch_id: batch.batch_id,
                material_code: batch.sku,
                material_name: batch.desc,
                qty: takeQty,
                from_loc: batch.location || 'ZONE-A',
                to_loc: 'STAGING-01',
                status: 'PENDING',
                priority: order.priority || 'NORMAL',
                created_at: Date.now()
            };
            taskDB.items.unshift(newTask);
            totalPicks++;

            needed -= takeQty;
            allocated += takeQty;
        }

        // Update line allocation
        line.qty_allocated = allocated;

        allocationResults.push({
            dn_no: order.dn_no || order.id,
            line_code: line.code,
            requested: line.qty,
            allocated: allocated,
            short: needed > 0 ? needed : 0
        });
    });

    // Update order status based on allocation
    let allAllocated = (order.lines || []).every(l => (l.qty_allocated || 0) >= (l.qty || 0));
    let anyAllocated = (order.lines || []).some(l => (l.qty_allocated || 0) > 0);

    if (allAllocated) {
        order.status = 'ALLOCATED';
        order.allocated_at = Date.now();
    } else if (anyAllocated) {
        order.status = 'ALLOCATED'; // Partial - proceed anyway
        order.partial_allocation = true;
    } else {
        order.status = 'BACKORDER';
    }
});

wave.picks_total = totalPicks;
wave.status = 'IN_PROGRESS';

// 5. Save all
global.set('wave_db', waveDB);
global.set('outbound_dn_db', dnDB);
global.set('internal_stock_list', inventory);
global.set('outbound_task_db', taskDB);

// 6. Prepare outputs
let msgWave = {
    topic: TOPIC_WAVE_STATE,
    payload: { version: "1.0", topics: [{ path: TOPIC_WAVE_STATE, type: "state", value: waveDB }] }
};

let msgDN = {
    topic: TOPIC_DN_STATE,
    payload: { version: "1.0", topics: [{ path: TOPIC_DN_STATE, type: "state", value: dnDB }] }
};

let msgInv = {
    topic: TOPIC_INVENTORY,
    payload: { version: "1.0", topics: [{ path: TOPIC_INVENTORY, type: "state", value: { last_updated: Date.now(), stock_items: inventory } }] }
};

let msgTasks = {
    topic: TOPIC_TASKS,
    payload: { version: "1.0", topics: [{ path: TOPIC_TASKS, type: "state", value: taskDB }] }
};

return [msgWave, msgDN, msgInv, msgTasks];

// TOPICS
const TOPIC_DN_STATE = "Henkelv2/Shanghai/Logistics/Outbound/State/DN_Workflow";
const TOPIC_INVENTORY = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Inventory_Level";
const TOPIC_TASKS = "Henkelv2/Shanghai/Logistics/Outbound/State/Picking_Tasks";

let action = msg.payload;
// Expected: { dn_no }

// 1. Get DBs
let dnDB = global.get('outbound_dn_db') || { items: [] };
let inventory = global.get('internal_stock_list') || [];
let taskDB = global.get('outbound_task_db') || { items: [] };

// 2. Find order
let order = dnDB.items.find(o => o.dn_no === action.dn_no || o.id === action.dn_no);
if (!order) {
    node.warn("Allocate DN Error: Order not found " + action.dn_no);
    return null;
}

// 3. Validate status
const canAllocate = ['RELEASED', 'APPROVED', 'NEW'].includes((order.status || '').toUpperCase());
if (!canAllocate) {
    node.warn("Allocate DN Error: Cannot allocate order in status " + order.status);
    return null;
}

order.status = 'ALLOCATING';

// 4. FEFO Allocation for each line
(order.lines || []).forEach(line => {
    let candidates = inventory.filter(item =>
        item.sku === line.code &&
        item.status === 'AVAILABLE'
    );

    candidates.sort((a, b) => {
        let dateA = a.expiry_date || 9999999999999;
        let dateB = b.expiry_date || 9999999999999;
        return dateA - dateB;
    });

    let needed = line.qty || 0;
    let allocated = 0;

    for (let batch of candidates) {
        if (needed <= 0) break;
        if (batch.qty <= 0) continue;

        let takeQty = Math.min(batch.qty, needed);

        batch.status = 'ALLOCATED';
        batch.allocated_to = order.dn_no || order.id;

        // Create pick task - for manufacturing, destination is production line
        let newTask = {
            task_id: 'PICK-' + Date.now() + '-' + Math.floor(Math.random() * 1000),
            dn_no: order.dn_no || order.id,
            batch_id: batch.batch_id,
            material_code: batch.sku,
            material_name: batch.desc,
            qty: takeQty,
            from_loc: batch.location || 'ZONE-A',
            to_loc: order.production_line || order.destination || 'LINE-SIDE-A',
            status: 'PENDING',
            context: 'MANUFACTURING',
            priority: order.priority || 'NORMAL',
